# Ativada pela URL 'listaFichas'. Lista as fichas de acordo com os filtros.
@login_required(login_url='loginUser')
def listaFichas(request):
    try: # 🌟 Bloco Try para capturar a exceção 🌟
        fichas = Ficha.objects.all().order_by('-dataCriacao')
        formFiltro = FichaFiltroForm(request.POST or None)

        if formFiltro.is_valid():
            f_nomeFicha = formFiltro.cleaned_data['f_nomeFicha']
            f_cliente = formFiltro.cleaned_data['f_cliente']
            f_autor = formFiltro.cleaned_data['f_autor']
            
            fichas = Ficha.objects.filter(
                Q(nomeFicha__contains=f_nomeFicha) &
                Q(cliente__contains=f_cliente) & 
                Q(autor__nome__contains=f_autor))

        # Esta é a linha que geralmente falha se houver erro no template
        return render(request, 'fichas_registradas.html', {'fichas': fichas, 'formFiltro': formFiltro}) 

    except Exception as e: # 🌟 Bloco Except para registrar a exceção no Heroku 🌟
        logger.exception("ERRO CRÍTICO NÃO TRATADO na view listaFichas") 
        return HttpResponseServerError("Erro Interno no Servidor. O traceback foi registrado nos logs do Heroku.")


# Ativada pela URL 'registrarFicha1'. Formulário inicial de uma ficha e cria a instancia no BD.
@login_required(login_url='loginUser')
def registrarFichaBase(request):
    form = FichaFormBase(request.POST or None)
    
    if form.is_valid():
        novaFicha = form.save()

        # Agora que essa Ficha existe, ela precisa também de uma Tabela
        # Da forma que o sistema foi modelado, essa tabela vai ter o mesmo ID da Ficha, que é sua origem

        # Ve se existe
        try:
          listing = Tabela.objects.get(pk = novaFicha.pk)
        except Tabela.DoesNotExist:
          listing = None
        
        # Se não existir ainda, ela cria
        if not listing:
          novaTabela = Tabela(pk = novaFicha.pk, origem = novaFicha)
          novaTabela.save()
        
        return redirect('editarFicha2', pk = novaFicha.pk)

    return render(request, 'registrarFichaBase.html', {'form': form})

