  def ordenarIngredientesPorQuantidade(tabela):
    itensReceitaOrdenada = Ficha_Ingrediente.objects.filter(ficha=fichaAtual).order_by('-pesoLiquido')
    textoOrdenado = ""
    
    for itemReceitaOrdenada in itensReceitaOrdenada:
      composicao = itemReceitaOrdenada.ingrediente.composicao  # isso funciona porque o FK existe
      if composicao:
          textoOrdenado += f"{itemReceitaOrdenada.nomeFantasia} ({composicao}), "
      else:
          textoOrdenado += f"{itemReceitaOrdenada.nomeFantasia}, "
    textoOrdenado = textoOrdenado[:-2] + "."  # Tira os 2 últimos caracteres para tirar o ", " do último e colocar ".""."
    return textoOrdenado.capitalize()
