# Ativada pela URL 'listaMembros'. Lista os membros do BD.
@login_required(login_url='loginUser')
def listaMembros(request):
    form = ChaveForm(request.POST or None)
    form_troca_senha = MudarSenha(request.POST or None)
    form_apaga_membro = ApagarMembro(request.POST or None)
    membros = Membro.objects.all().order_by(Lower('nome'))
    eh_admin = False

    chave = "[Logue com o admin para ver]"
    if request.user.username == 'admin':
      eh_admin = True
      aux = Chave.objects.last()
      chave = aux.key

    return render(request, 'usuarios_registrados.html', {'membros': membros, 'chave': chave, 'eh_admin': eh_admin, 'form': form, 'form_troca_senha': form_troca_senha, 'form_apaga_membro': form_apaga_membro})
 
def mudaChave(request):
  form = ChaveForm()
  if request.is_ajax():
    form = ChaveForm(request.POST)
    if form.is_valid():
      form.save()

      data = {
        'ajax_message': 'Chave alterada com sucesso!',
        'nova_chave': request.POST['key']
      }
      response = JsonResponse(data)
      return response
    else:
      data = {
        'ajax_message': 'A chave não pôde ser alterada!'
      }
      response = JsonResponse(data)
      response.status_code = 403
      return response

def trocaSenha(request):
  form = MudarSenha()
  if request.is_ajax():
    form = MudarSenha(request.POST)
    if form.is_valid():
      nova_senha = form.cleaned_data['nova_senha']
      encryption = make_password(nova_senha)
      aux = form.cleaned_data['usuario']
      membro = Membro.objects.get(nome=aux)
      usuario = User.objects.get(membro=membro)
      usuario.password = encryption
      usuario.save()

      data = {
        'ajax_message': 'Senha de '+membro.nome+' alterada com sucesso!',
      }
      response = JsonResponse(data)
      return response
    else:
      data = {
        'ajax_message': 'A senha não pode ser alterada!'
      }
      response = JsonResponse(data)
      response.status_code = 403
      return response

def deletaMembro(request):
  form = ApagarMembro()
  if request.is_ajax():
    form = ApagarMembro(request.POST)
    if form.is_valid():
      membroExcluido = form.cleaned_data['membroExcluido']
      membroDestino = form.cleaned_data['membroDestino']

      ingredientesTrasnferencia = Ingrediente.objects.filter(autorIng=membroExcluido)
      numIT = ingredientesTrasnferencia.count()
      for ingrediente in ingredientesTrasnferencia:
        ingrediente.autorIng = membroDestino
        ingrediente.save()
        
      fichasTrasnferencia = Ficha.objects.filter(autor=membroExcluido)
      numFT = fichasTrasnferencia.count()
      for ficha in fichasTrasnferencia:
        ficha.autor = membroDestino
        ficha.save()

      usuarioExcluido = membroExcluido.usuario
      usuarioExcluido.delete()
      
      ajax_mes = 'Transferidos '+str(numFT)+' fichas e '+str(numIT)+' ingredientes de '+membroExcluido.nome+' para '+membroDestino.nome+'!'
      data = {
        'ajax_message': ajax_mes,
      }
      response = JsonResponse(data)
      return response
    else:
      # Transforma erros dos campos em uma string pra devolver no JSON
      strErros = ''
      for key in form.errors:
        if strErros != '':
          strErros += '; '
        campo = form.fields[key].label
        erro = form.errors[key][0]
        strErros = "Erro no campo <b>"+campo+"</b>: "+erro
      data = {
        'ajax_message': 'O membro não pode ser excluído!',
        'form_errors': strErros
      }
      response = JsonResponse(data)
      response.status_code = 403
      return response

# Ativada pela URL 'registrarMembro'. Faz formulário de novo membro e salva no BD se tiver a chave de segurança 
def registrarMembro(request):
  logout(request)  # Sempre que criar um usuário ele estará deslogado, pra não acontecer de criar um usuário e parecer estar logado nele por já estar logado quando criou

  form = MembroForm(request.POST or None)
  if form.is_valid():
      input_usuario = form.cleaned_data['chave']
      chave = Chave.objects.last().key

      s1 = form.cleaned_data['senha1']
      s2 = form.cleaned_data['senha2']

      if User.objects.filter(username=form.cleaned_data['nome']):
        messages.error(request, "Já existe um usuário com esse nome. Não foi possível realizar o cadastro.")
      elif s1 != s2:
        messages.error(request, "As senhas não conferem. Não foi possível realizar o cadastro.")
      elif input_usuario != chave:
        messages.error(request, "Chave incorreta. Não foi possível realizar o cadastro.")
      else:
        post = form.save(commit=False)
        aux = User.objects.create_user(
          form.cleaned_data['nome'],
          password=form.cleaned_data['senha1'],
          email=form.cleaned_data['email'])
        post.usuario = aux
        post.save()
        
        return redirect('listaFichas')

  return render(request, 'registrarMembro.html', {'form': form})

# Ativada pela URL 'loginUser'. Página de login.
def loginUser(request):
  logout(request)  # Garante que sempre que vier pra página de login ele estará deslogado
  form = LoginForm(request.POST or None) 
  if form.is_valid():
      username = form.cleaned_data['username']
      password = form.cleaned_data['password']

      user = authenticate(username=username, password=password)
      if user is not None:
        login(request, user)
      else:
        messages.error(request, "Não foi possível fazer login")

      return redirect('listaFichas')  

  return render(request, 'login.html', {'form': form})

# Ativada pela URL 'logoutUser'. Faz o logout e envia para fazer login
def logoutUser(request):
  logout(request)
  return redirect('loginUser')



