# Ativada pela URL 'listaIngredientes'. Lista os ingredientes do BD de acordo com os filtros.
@login_required(login_url='loginUser')
def listaIngredientes(request):
    ingredientes = Ingrediente.objects.filter(
        dataCriacao__year__gte=2024 
    ).order_by('nomeIng')
    formFiltro = IngredienteFiltroForm(request.POST or None)

    if formFiltro.is_valid():
      f_nomeIng = formFiltro.cleaned_data['f_nomeIng']
      f_origemDosDados = formFiltro.cleaned_data['f_origemDosDados']
      f_autorIng = formFiltro.cleaned_data['f_autorIng']
      
      ingredientes = Ingrediente.objects.filter(
        Q(nomeIng__contains=f_nomeIng) &
        Q(origemDosDados__contains=f_origemDosDados) & 
        Q(autorIng__nome__contains=f_autorIng))
        
    return render(request, 'ingredientes_registrados.html', {'ingredientes': ingredientes, 'formFiltro': formFiltro})

