# Ativada pela URL 'registrarIngrediente'. Faz formulário de novo ingrediente e salva no BD.
@login_required(login_url='loginUser')
def registrarIngrediente(request):
  form = IngredienteForm(request.POST or None)

  if form.is_valid():
    if Ingrediente.objects.filter(nomeIng=form.cleaned_data['nomeIng']):
      messages.error(request, "Já existe um ingrediente com esse nome. Não foi possível realizar o cadastro.")
    else:
      ing = form.save(commit = False)
      att100gIngrediente(ing)
      ing.save

      return redirect('listaIngredientes')

  return render(request, 'registrarIngrediente.html', {'form': form})

# Ativada pela URL 'editarIngrediente'. Formulário já instanciado de um ingrediente para edição 
@login_required(login_url='loginUser')
def editarIngrediente(request, pk): 
  ingredienteAtual = Ingrediente.objects.get(pk = pk)
  form = IngredienteForm(instance = ingredienteAtual)

  if(request.method == 'POST'):
    form = IngredienteForm(request.POST, instance = ingredienteAtual)

    if(form.is_valid()):
      if Ingrediente.objects.filter(nomeIng=form.cleaned_data['nomeIng']).exclude(pk=ingredienteAtual.pk):
        messages.error(request, "Já existe um ingrediente com esse nome. Não foi possível realizar o cadastro.")
      else:
        att100gIngrediente(ingredienteAtual)
        ingredienteAtual.save()
        return redirect('listaIngredientes')

  return render(request, 'registrarIngrediente.html', {'form': form})

# Ativada pela URL 'upload'. Faz o upload dos ingredientes de um arquivo txt externo.
@login_required(login_url='loginUser')
def upload(request):
  template = 'upload.html'
  prompt = {
    'order': 'Order of the CSV should be ID_func, ID_atv, Data '
  }
  if request.method == 'GET':
    return render(request, template, prompt)
  
  csv_file = request.FILES ['files']
  if not csv_file.name.endswith('.txt'):
    messages.error(request, 'Coloque um arquivo TXT separado por TAB (extraído do excel desktop)')
  data_set = csv_file.read().decode('utf-8') 
  io_string = io.StringIO(data_set)
  next (io_string) # Pra ignorar a primeira linha (cabeçalho)

  membro = Membro.objects.filter(nome = request.user.username)
  
  for column in csv.reader(io_string, delimiter="\t", quotechar="|"):
    _, created = Ingrediente.objects.update_or_create(
        autorIng = Membro.objects.first(),
        nomeIng = column[2],
        origemDosDados = column[0],
        addManualmente = 1,
        numRef = column[1],
        dataCriacao = "2019-09-26",

        # Valores nutrientes
        proteinas = float(column[6]),
        gordTotais = float(column[7]), # Na TACO está como Lipideos
        carboidratos = float(column[9]),
        fibras = float(column[10]),
        energiakcal = float(column[4]),
        energiaKJ = float(column[5]),
        calcio = float(column[12]),
        ferro = float(column[17]),
        magnesio = float(column[13]),
        fosforo = float(column[16]),
        potassio = float(column[19]),
        sodio = float(column[18]),
        zinco = float(column[21]),
        cobre = float(column[20]),
        manganes = float(column[15]),
        retinol = float(column[22]),
        RE = float(column[23]),
        vitaminaARAE = float(column[24]),
        vitaminaC = float(column[29]),
        tiamina = float(column[25]),
        riboflavina = float(column[26]),
        niancina = float(column[28]),
        piridoxina = float(column[27]),
        gordSat = float(column[31]),
        gordTrans = float(column[52]) + float(column[53]), # Gorduras trans é 18:1t + 18:2t
        gordPoli = float(column[33]),
        gordMono = float(column[32]),
        colesterol = float(column[8])
        )
  
  #Atualiza o 100g desses ingredientes
  ingredientes = Ingrediente.objects.all()
  for ingrediente in ingredientes:
    att100gIngrediente(ingrediente)

  return render (request, template)

# Ativada pela URL 'deletarIngrediente'. Deleta um ingrediente específico
@login_required(login_url='loginUser')
def deletarIngrediente(request, pk):
  ingrediente = Ingrediente.objects.get(pk=pk)
  if request.method == "POST":
    ingrediente.delete()
  return redirect('listaIngredientes')



